using TranSmart.Core.Result;
using TranSmart.Data;
using TranSmart.Data.Paging;
using TranSmart.Domain.Entities.Organization;
using TranSmart.Domain.Models;
using Microsoft.EntityFrameworkCore;
using System.Collections.Generic;
using System;
using System.Linq;
using System.Threading.Tasks;

namespace TranSmart.Service.Organization
{
    public partial interface IDepartmentService : IBaseService<Department>
    {

    }

    public partial class DepartmentService : BaseService<Department>, IDepartmentService
    {
        public DepartmentService(IUnitOfWork uow) : base(uow)
        {

        }

        public override async Task Validation(Department item, Result<Department> executionResult)
        {
            if (await UOW.GetRepositoryAsync<Department>().HasRecordsAsync(x => x.Name == item.Name && x.Status == true && x.ID != item.ID))
            {
                executionResult.AddMessageItem(new MessageItem(nameof(Department.Name), "Name already exists"));
            }
        }
        public override async Task<Department> GetById(Guid id)
        {
            return await UOW.GetRepositoryAsync<Department>().SingleAsync(
                predicate: x => x.ID == id,
                include: i => i.Include(x => x.Shift).Include(x => x.WeekOffSetup).Include(x => x.WorkHoursSetting),
                orderBy: o => o.OrderByDescending(x => x.AddedAt));
        }

        public override async Task<IEnumerable<Department>> GetList(string orderBy)
        {
            return await UOW.GetRepositoryAsync<Department>().GetListAsync(orderBy, x => x.Status == true);
        }

        public override async Task<IPaginate<Department>> GetPaginate(BaseSearch search)
        {
            return await UOW.GetRepositoryAsync<Department>().GetPageListAsync(
                predicate: x => (string.IsNullOrEmpty(search.Name)
                     || x.Name.Contains(search.Name)
                     || x.Email.Contains(search.Name)
                     || x.Shift.Name.Contains(search.Name)),
                include: i => i.Include(x => x.Shift).Include(x => x.WeekOffSetup).Include(x => x.WorkHoursSetting),
                index: search.Page, size: search.Size, sortBy: search.SortBy ?? "Name", ascending: !search.IsDescend);
        }
    }
